// // This module implements a 16-bit shift register with support for both left and right shifts based on a control signal.
// Input ports:
//     data: 16-bit input data.
//     control: 2-bit control signal.
// Output ports:
//     out: 16-bit output of the shift register.

module ShiftRegister (
    input [15:0] data,
    input [1:0] control,
    output reg [15:0] out
);
    always @(*) begin
        case (control)
            2'b00: out = data; // No shift
            2'b01: out = data >> 1; // Left shift
            2'b10: out = data << 1; // Right shift
            2'b11: out = data; // No shift
            default: out = 16'b0;
        endcase
    end
endmodule
